// CreateIndexes 创建索引（非阻塞，后台构建）
func (m *MongoDB) CreateIndexes() error {
	// 临时调试，循环查询下构建状态
	/* for {
		time.Sleep(2 * time.Second)
		p, _ := m.db.GetIndexBuildProgress(context.Background())
		fmt.Println(p)
	} */
	// Init Indexes
	for _, index := range m.cfg.Mongodb.Indexes {
		for _, key := range index.Keys {
			items := strings.Split(key, "@")
			unique := false
			if len(items) != 1 {
				if items[1] != "true" && items[1] != "false" {
					return fmt.Errorf("index key unique %v is invalid, please check config", key)
				}
				unique = items[1] == "true"
			}
			keyItems := strings.Split(items[0], ",")

			// 检查索引是否已存在
			if b, err := m.db.HasIndexesPrefixMatch(context.Background(), index.Collection, keyItems); err != nil {
				return err
			} else if !b {
				// 索引不存在，开始创建
				logger.Info("mongo start create index: collection=%s fields=%v unique=%v",
					index.Collection, keyItems, unique)

				indexOpts := mongodb.IndexOptions{
					Unique:     unique,
					Background: true, // 后台构建，不阻塞
					Sparse:     true,
				}
				// 异步创建索引（不阻塞启动）
				m.db.CreateIndexesAsyncWithMonitoring(context.Background(), index.Collection, keyItems, indexOpts,
					nil,
					// 完成回调 - 处理最终结果
					func(err error) {
						if err != nil {
							logger.Error("mongo create index failed: collection=%s index=%s error=%v",
								index.Collection, strings.Join(keyItems, "_"), err)
						} else {
							logger.Info("mongo create index success: collection=%s index=%s",
								index.Collection, strings.Join(keyItems, "_"))
						}
					})
			} else {
				logger.Info("mongo index already exists, skip create: collection (%s) fields (%v)",
					index.Collection, strings.Join(keyItems, " "))
			}
		}
	}
	return nil
}

